// Some portions generated by Co-Pilot
import { describe, it, expect } from "vitest";
import getVendorIdentifier from "../vendors";

describe("getVendorIdentifier", () => {
  it("converts vendor name to lowercase", () => {
    const vendor = { name: "Eclipse Temurin", icon: "/icons/temurin.svg" };
    expect(getVendorIdentifier(vendor)).toBe("eclipsetemurin");
  });

  it("removes spaces from vendor name", () => {
    const vendor = { name: "IBM Semeru", icon: "/icons/ibm.svg" };
    expect(getVendorIdentifier(vendor)).toBe("ibmsemeru");
  });

  it("handles single word vendor name", () => {
    const vendor = { name: "Azul", icon: "/icons/azul.svg" };
    expect(getVendorIdentifier(vendor)).toBe("azul");
  });

  it("handles multiple spaces between words", () => {
    const vendor = { name: "Red   Hat", icon: "/icons/redhat.svg" };
    expect(getVendorIdentifier(vendor)).toBe("redhat");
  });

  it("handles already lowercase name", () => {
    const vendor = { name: "adoptium", icon: "/icons/adoptium.svg" };
    expect(getVendorIdentifier(vendor)).toBe("adoptium");
  });
});
